package com.hcmute.bookstore.dto.admin;

public class PredictionJobResponse {
    private String jobId;
    private String status;
    private DashboardRevenuePredictionResponse prediction;
    private String message;

    public PredictionJobResponse() {
    }

    public PredictionJobResponse(String jobId, String status, DashboardRevenuePredictionResponse prediction, String message) {
        this.jobId = jobId;
        this.status = status;
        this.prediction = prediction;
        this.message = message;
    }

    public static PredictionJobResponse pending(String jobId) {
        return new PredictionJobResponse(jobId, "PENDING", null, null);
    }

    public static PredictionJobResponse done(String jobId, DashboardRevenuePredictionResponse prediction) {
        return new PredictionJobResponse(jobId, "DONE", prediction, null);
    }

    public static PredictionJobResponse failed(String jobId, String message) {
        return new PredictionJobResponse(jobId, "FAILED", null, message);
    }

    public String getJobId() {
        return jobId;
    }

    public void setJobId(String jobId) {
        this.jobId = jobId;
    }

    public String getStatus() {
        return status;
    }

    public void setStatus(String status) {
        this.status = status;
    }

    public DashboardRevenuePredictionResponse getPrediction() {
        return prediction;
    }

    public void setPrediction(DashboardRevenuePredictionResponse prediction) {
        this.prediction = prediction;
    }

    public String getMessage() {
        return message;
    }

    public void setMessage(String message) {
        this.message = message;
    }
}

import 'package:flutter_riverpod/flutter_riverpod.dart';

import '../core/api_client.dart';
import '../core/session_storage.dart';
import '../features/auth/data/auth_api.dart';
import '../features/auth/data/auth_repository.dart';
import '../features/dashboard/data/dashboard_api.dart';
import '../features/orders/data/order_api.dart';
import '../features/products/data/product_api.dart';
import '../chat/data/chat_api.dart';
import '../chat/data/socket_service.dart';
import '../chat/data/chat_repository.dart';
import '../features/customers/data/customer_api.dart';

final sessionStorageProvider = Provider<SessionStorage>((ref) {
  throw UnimplementedError('SessionStorage override required');
});

final apiClientProvider = Provider<ApiClient>((ref) {
  throw UnimplementedError('ApiClient override required');
});

final authRepositoryProvider = Provider<AuthRepository>((ref) {
  final apiClient = ref.read(apiClientProvider);
  return AuthRepository(AuthApi(apiClient), ref.read(sessionStorageProvider));
});

final dashboardApiProvider = Provider<DashboardApi>((ref) {
  return DashboardApi(ref.read(apiClientProvider));
});

final productApiProvider = Provider<ProductApi>((ref) {
  return ProductApi(ref.read(apiClientProvider));
});

final orderApiProvider = Provider<OrderApi>((ref) {
  return OrderApi(ref.read(apiClientProvider));
});

final chatApiProvider = Provider<ChatApi>((ref) {
  final apiClient = ref.watch(apiClientProvider);
  return ChatApi(apiClient);
});

final socketServiceProvider = Provider<SocketService>((ref) {
  final apiClient = ref.watch(apiClientProvider);
  return SocketService(apiClient);
});

final chatRepositoryProvider = Provider<ChatRepository>((ref) {
  final api = ref.watch(chatApiProvider);
  final socket = ref.watch(socketServiceProvider);
  return ChatRepository(api, socket);
});
final customerApiProvider = Provider<CustomerApi>(
      (ref) => CustomerApi(ref.read(apiClientProvider)),
);

