import '../../../core/api_client.dart';
import 'coupon_models.dart';

class CouponApi {
  CouponApi(this._client);

  final ApiClient _client;

  Future<List<Coupon>> fetchCoupons({
    String? search,
    String? status,
    String? scope,
  }) async {
    final response = await _client.dio.get(
      '/admin/coupons/all',
      queryParameters: {
        if (search != null && search.isNotEmpty) 'search': search,
        if (status != null && status.isNotEmpty) 'status': status,
        if (scope != null && scope.isNotEmpty) 'scope': scope,
      },
    );
    final data = response.data as List<dynamic>;
    return data.map((e) => Coupon.fromJson(e as Map<String, dynamic>)).toList();
  }

  Future<Coupon> fetchCoupon(String id) async {
    final response = await _client.dio.get('/admin/coupons/$id');
    return Coupon.fromJson(response.data as Map<String, dynamic>);
  }

  Future<Coupon> create(CouponRequest request) async {
    final response = await _client.dio.post(
      '/admin/coupons/create',
      data: request.toJson(),
    );
    return Coupon.fromJson(response.data as Map<String, dynamic>);
  }

  Future<Coupon> update(String id, CouponRequest request) async {
    final response = await _client.dio.put(
      '/admin/coupons/update/$id',
      data: request.toJson(),
    );
    return Coupon.fromJson(response.data as Map<String, dynamic>);
  }

  Future<void> delete(String id) async {
    await _client.dio.delete('/admin/coupons/delete/$id');
  }

  Future<CouponStats> fetchStats() async {
    final response = await _client.dio.get('/admin/coupons/stats');
    return CouponStats.fromJson(response.data as Map<String, dynamic>);
  }
}

class Coupon {
  Coupon({
    required this.id,
    required this.code,
    required this.discountPercent,
    required this.discountAmount,
    required this.minOrderValue,
    required this.maxDiscount,
    required this.expiryDate,
    required this.usageLimit,
    required this.usedCount,
    required this.customerId,
    required this.customerName,
    required this.status,
  });

  final String id;
  final String code;
  final int? discountPercent;
  final int? discountAmount;
  final int? minOrderValue;
  final int? maxDiscount;
  final DateTime? expiryDate;
  final int? usageLimit;
  final int usedCount;
  final String? customerId;
  final String? customerName;
  final String? status;

  factory Coupon.fromJson(Map<String, dynamic> json) {
    return Coupon(
      id: json['id']?.toString() ?? '',
      code: json['code']?.toString() ?? '',
      discountPercent: (json['discountPercent'] as num?)?.toInt(),
      discountAmount: (json['discountAmount'] as num?)?.toInt(),
      minOrderValue: (json['minOrderValue'] as num?)?.toInt(),
      maxDiscount: (json['maxDiscount'] as num?)?.toInt(),
      expiryDate: _parseDate(json['expiryDate']),
      usageLimit: (json['usageLimit'] as num?)?.toInt(),
      usedCount: (json['usedCount'] as num?)?.toInt() ?? 0,
      customerId: json['customerId']?.toString(),
      customerName: json['customerName']?.toString(),
      status: json['status']?.toString(),
    );
  }

  bool get isPercent => (discountPercent ?? 0) > 0;

  bool get isAmount => (discountAmount ?? 0) > 0;

  String get scopeLabel => (customerId == null || customerId!.isEmpty)
      ? 'Toàn hệ thống'
      : 'Cá nhân';

  String get resolvedStatus {
    final now = DateTime.now();
    final expiry = expiryDate;
    if (expiry != null && expiry.isBefore(now)) {
      return 'EXPIRED';
    }
    final limit = usageLimit;
    if (limit != null && usedCount >= limit) {
      return 'USED_UP';
    }
    return status?.isNotEmpty == true ? status! : 'ACTIVE';
  }

  static DateTime? _parseDate(dynamic value) {
    if (value == null) return null;
    if (value is String) {
      return DateTime.tryParse(value);
    }
    return null;
  }
}

class CouponRequest {
  CouponRequest({
    required this.code,
    this.discountPercent,
    this.discountAmount,
    this.minOrderValue,
    this.maxDiscount,
    required this.expiryDate,
    this.usageLimit,
    this.customerId,
  });

  final String code;
  final int? discountPercent;
  final int? discountAmount;
  final int? minOrderValue;
  final int? maxDiscount;
  final DateTime expiryDate;
  final int? usageLimit;
  final String? customerId;

  Map<String, dynamic> toJson() {
    return {
      'code': code,
      'discountPercent': discountPercent,
      'discountAmount': discountAmount,
      'minOrderValue': minOrderValue,
      'maxDiscount': maxDiscount,
      'expiryDate': expiryDate.toIso8601String(),
      'usageLimit': usageLimit,
      'customerId': customerId?.isEmpty == true ? null : customerId,
    };
  }
}

class CouponStats {
  CouponStats({
    required this.activeCount,
    required this.expiringSoonCount,
    required this.totalUsedCount,
    required this.topUsedCode,
    required this.topUsedCount,
  });

  final int activeCount;
  final int expiringSoonCount;
  final int totalUsedCount;
  final String? topUsedCode;
  final int topUsedCount;

  factory CouponStats.fromJson(Map<String, dynamic> json) {
    return CouponStats(
      activeCount: (json['activeCount'] as num?)?.toInt() ?? 0,
      expiringSoonCount: (json['expiringSoonCount'] as num?)?.toInt() ?? 0,
      totalUsedCount: (json['totalUsedCount'] as num?)?.toInt() ?? 0,
      topUsedCode: json['topUsedCode']?.toString(),
      topUsedCount: (json['topUsedCount'] as num?)?.toInt() ?? 0,
    );
  }
}

import 'coupon_api.dart';
import 'coupon_models.dart';

class CouponRepository {
  CouponRepository(this._api);

  final CouponApi _api;

  Future<List<Coupon>> fetchCoupons({
    String? search,
    String? status,
    String? scope,
  }) {
    return _api.fetchCoupons(search: search, status: status, scope: scope);
  }

  Future<Coupon> create(CouponRequest request) => _api.create(request);

  Future<Coupon> update(String id, CouponRequest request) => _api.update(id, request);

  Future<void> delete(String id) => _api.delete(id);

  Future<CouponStats> fetchStats() => _api.fetchStats();
}

import 'package:flutter_riverpod/flutter_riverpod.dart';

import '../../../app/providers.dart';
import '../data/coupon_models.dart';
import '../data/coupon_repository.dart';

class CouponState {
  CouponState({
    required this.items,
    required this.isLoading,
    required this.search,
    required this.statusFilter,
    required this.scopeFilter,
    required this.errorMessage,
    required this.stats,
  });

  final List<Coupon> items;
  final bool isLoading;
  final String search;
  final String statusFilter;
  final String scopeFilter;
  final String? errorMessage;
  final CouponStats? stats;

  factory CouponState.initial() {
    return CouponState(
      items: const [],
      isLoading: false,
      search: '',
      statusFilter: 'all',
      scopeFilter: 'all',
      errorMessage: null,
      stats: null,
    );
  }

  CouponState copyWith({
    List<Coupon>? items,
    bool? isLoading,
    String? search,
    String? statusFilter,
    String? scopeFilter,
    String? errorMessage,
    CouponStats? stats,
  }) {
    return CouponState(
      items: items ?? this.items,
      isLoading: isLoading ?? this.isLoading,
      search: search ?? this.search,
      statusFilter: statusFilter ?? this.statusFilter,
      scopeFilter: scopeFilter ?? this.scopeFilter,
      errorMessage: errorMessage,
      stats: stats ?? this.stats,
    );
  }
}

class CouponNotifier extends StateNotifier<CouponState> {
  CouponNotifier(this._repository) : super(CouponState.initial());

  final CouponRepository _repository;

  Future<void> loadCoupons({
    String? search,
    String? status,
    String? scope,
  }) async {
    state = state.copyWith(isLoading: true, errorMessage: null);
    try {
      final items = await _repository.fetchCoupons(
        search: search ?? state.search,
        status: status ?? state.statusFilter,
        scope: scope ?? state.scopeFilter,
      );
      state = state.copyWith(
        isLoading: false,
        items: items,
        search: search ?? state.search,
        statusFilter: status ?? state.statusFilter,
        scopeFilter: scope ?? state.scopeFilter,
      );
    } catch (e) {
      state = state.copyWith(
        isLoading: false,
        errorMessage: e.toString(),
      );
    }
  }

  Future<void> refreshStats() async {
    try {
      final stats = await _repository.fetchStats();
      state = state.copyWith(stats: stats, errorMessage: null);
    } catch (e) {
      state = state.copyWith(errorMessage: e.toString());
    }
  }

  Future<void> create(CouponRequest request) async {
    await _repository.create(request);
    await loadCoupons();
    await refreshStats();
  }

  Future<void> update(String id, CouponRequest request) async {
    await _repository.update(id, request);
    await loadCoupons();
    await refreshStats();
  }

  Future<void> delete(String id) async {
    await _repository.delete(id);
    state = state.copyWith(items: state.items.where((e) => e.id != id).toList());
    await refreshStats();
  }
}

final couponRepositoryProvider = Provider<CouponRepository>((ref) {
  final api = ref.read(couponApiProvider);
  return CouponRepository(api);
});

final couponNotifierProvider = StateNotifierProvider<CouponNotifier, CouponState>((ref) {
  return CouponNotifier(ref.read(couponRepositoryProvider));
});

import 'package:flutter/material.dart';
import 'package:flutter_animate/flutter_animate.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:intl/intl.dart';

import '../../../theme/admin_theme.dart';
