  });

  final Coupon coupon;
  final String Function(num value) formatCurrency;
  final VoidCallback onEdit;
  final VoidCallback onDelete;

  @override
  Widget build(BuildContext context) {
    final status = coupon.resolvedStatus;
    final statusColor = _statusColor(status);
    final expiryText = coupon.expiryDate == null
        ? '—'
        : DateFormat('dd/MM/yyyy').format(coupon.expiryDate!);

    return Container(
      margin: const EdgeInsets.only(bottom: 12),
      padding: const EdgeInsets.all(14),
      decoration: _cardDecoration,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
                decoration: BoxDecoration(
                  color: AdminColors.surfaceAlt,
                  borderRadius: BorderRadius.circular(12),
                ),
                child: Text(coupon.code, style: const TextStyle(fontWeight: FontWeight.w700)),
              ),
              const SizedBox(width: 8),
              _StatusChip(label: _statusLabel(status), color: statusColor),
              const Spacer(),
              PopupMenuButton<String>(
                onSelected: (value) {
                  if (value == 'edit') {
                    onEdit();
                  } else if (value == 'delete') {
                    onDelete();
                  }
                },
                itemBuilder: (context) => const [
                  PopupMenuItem(value: 'edit', child: Text('Chỉnh sửa')),
                  PopupMenuItem(value: 'delete', child: Text('Xóa')),
                ],
              ),
            ],
          ),
          const SizedBox(height: 10),
          Row(
            children: [
              Expanded(
                child: _InfoTile(
                  label: 'Loại giảm',
                  value: coupon.isPercent
                      ? 'Giảm ${coupon.discountPercent}%'
                      : 'Giảm ${formatCurrency(coupon.discountAmount ?? 0)}',
                ),
              ),
              Expanded(
                child: _InfoTile(
                  label: 'Đơn tối thiểu',
                  value: formatCurrency(coupon.minOrderValue ?? 0),
                ),
              ),
            ],
          ),
          const SizedBox(height: 8),
          Row(
            children: [
              Expanded(
                child: _InfoTile(
                  label: 'Giảm tối đa',
                  value: formatCurrency(coupon.maxDiscount ?? 0),
                ),
              ),
              Expanded(
                child: _InfoTile(
                  label: 'HSD',
                  value: expiryText,
                ),
              ),
            ],
          ),
          const SizedBox(height: 8),
          Row(
            children: [
              Expanded(
                child: _InfoTile(
                  label: 'Đã dùng',
                  value: '${coupon.usedCount} / ${coupon.usageLimit ?? '∞'}',
                ),
              ),
              Expanded(
                child: _InfoTile(
                  label: 'Áp dụng',
                  value: coupon.customerName?.isNotEmpty == true
                      ? coupon.customerName!
                      : coupon.scopeLabel,
                ),
              ),
            ],
          ),
        ],
      ),
    );
  }

  Color _statusColor(String status) {
    switch (status) {
      case 'ACTIVE':
        return AdminColors.success;
      case 'USED_UP':
        return AdminColors.warning;
      case 'EXPIRED':
        return AdminColors.danger;
      default:
        return AdminColors.textSecondary;
    }
  }

  String _statusLabel(String status) {
    switch (status) {
      case 'ACTIVE':
        return 'Hoạt động';
      case 'USED_UP':
        return 'Hết lượt';
      case 'EXPIRED':
        return 'Hết hạn';
      default:
        return '—';
    }
  }
}

