  borderRadius: BorderRadius.all(Radius.circular(18)),
  boxShadow: [
    BoxShadow(color: Color(0x11000000), blurRadius: 10, offset: Offset(0, 6)),
  ],
);

import 'dart:async';

import 'package:dio/dio.dart';
import 'package:flutter/foundation.dart';

import '../../../core/api_client.dart';
import '../data/dashboard_models.dart';

class PredictionTimeoutException implements Exception {
  PredictionTimeoutException(this.message);

  final String message;

  @override
  String toString() => message;
}

class PredictionService {
  PredictionService(this._client);

  final ApiClient _client;

  static const _predictionPath = '/admin/dashboard/revenue-prediction';
  static const _jobPath = '/admin/dashboard/revenue-prediction/jobs';
  static const _retryDelay = Duration(seconds: 2);
  static const _pollDelay = Duration(seconds: 3);
  static const _maxRetries = 2;
  static const _maxPolls = 20;

  Future<DashboardRevenuePredictionResponse> fetchPrediction() async {
    try {
      final response = await _retryOnTimeout(() => _client.dio.get(_predictionPath));
      return DashboardRevenuePredictionResponse.fromJson(response.data as Map<String, dynamic>);
    } on DioException catch (error) {
      if (_isTimeout(error)) {
        debugPrint('Prediction timeout, switching to polling flow: ${error.message}');
        return _fetchWithPolling();
      }
      debugPrint('Prediction request failed: ${error.message}');
      rethrow;
    } catch (error, stackTrace) {
      debugPrint('Prediction request error: $error');
      debugPrint('$stackTrace');
      rethrow;
    }
  }

  Future<Response<dynamic>> _retryOnTimeout(Future<Response<dynamic>> Function() request) async {
    var attempt = 0;
    while (true) {
      try {
        return await request();
      } on DioException catch (error) {
        if (_isTimeout(error) && attempt < _maxRetries) {
          attempt += 1;
          debugPrint('Prediction timeout, retry $attempt/$_maxRetries');
          await Future.delayed(_retryDelay);
          continue;
        }
        rethrow;
      }
    }
  }

  Future<DashboardRevenuePredictionResponse> _fetchWithPolling() async {
    final jobId = await _createPredictionJob();
    for (var attempt = 0; attempt < _maxPolls; attempt += 1) {
      await Future.delayed(_pollDelay);
      final status = await _getJobStatus(jobId);
      if (status.isDone) {
        return status.prediction!;
      }
      if (status.isFailed) {
        throw Exception(status.message ?? 'Prediction job failed.');
      }
    }
    throw PredictionTimeoutException(
      'Máy chủ đang xử lý dữ liệu lâu hơn bình thường. Vui lòng thử lại.',
    );
  }

  Future<String> _createPredictionJob() async {
    try {
      final response = await _client.dio.post(_jobPath);
      final data = response.data as Map<String, dynamic>;
      final jobId = data['jobId']?.toString();
      if (jobId == null || jobId.isEmpty) {
        throw Exception('Prediction job id missing.');
      }
      return jobId;
    } on DioException catch (error) {
      debugPrint('Create prediction job failed: ${error.message}');
      if (_isTimeout(error)) {
        throw PredictionTimeoutException(
          'Máy chủ đang xử lý dữ liệu lâu hơn bình thường. Vui lòng thử lại.',
        );
      }
      rethrow;
    }
  }

  Future<_PredictionJobStatus> _getJobStatus(String jobId) async {
    try {
      final response = await _client.dio.get('$_jobPath/$jobId');
      final data = response.data as Map<String, dynamic>;
      return _PredictionJobStatus.fromJson(data);
    } on DioException catch (error) {
      debugPrint('Prediction polling failed: ${error.message}');
      if (_isTimeout(error)) {
        return const _PredictionJobStatus.pending();
      }
      rethrow;
    }
  }

  bool _isTimeout(DioException error) {
    return error.type == DioExceptionType.connectionTimeout ||
        error.type == DioExceptionType.sendTimeout ||
        error.type == DioExceptionType.receiveTimeout ||
        error.error is TimeoutException;
  }
}

class _PredictionJobStatus {
  const _PredictionJobStatus({this.status, this.prediction, this.message});

  const _PredictionJobStatus.pending() : status = 'PENDING', prediction = null, message = null;

  final String? status;
  final DashboardRevenuePredictionResponse? prediction;
  final String? message;

  bool get isDone => status == 'DONE' && prediction != null;
  bool get isFailed => status == 'FAILED';

  factory _PredictionJobStatus.fromJson(Map<String, dynamic> json) {
    final status = json['status']?.toString();
    final predictionData = json['prediction'];
    return _PredictionJobStatus(
      status: status,
      prediction: predictionData is Map<String, dynamic>
          ? DashboardRevenuePredictionResponse.fromJson(predictionData)
          : null,
      message: json['message']?.toString(),
    );
  }
}

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:flutter_animate/flutter_animate.dart';

import '../../../app/providers.dart';
import '../../../widgets/placeholder_screen.dart';
import '../../../theme/admin_theme.dart';
import '../../customers/presentation/customers_screen.dart';
import '../../auth/presentation/admin_login_screen.dart';
// Giả định import cho ChatListScreen nếu bạn đã có file này
import '../../../../chat/presentation/chat_list_screen.dart';

class ManagementScreen extends ConsumerStatefulWidget {
  const ManagementScreen({super.key});

  @override
  ConsumerState<ManagementScreen> createState() => _ManagementScreenState();
}

class _ManagementScreenState extends ConsumerState<ManagementScreen> {
  bool _hasUnread = false;

  @override
  void initState() {
    super.initState();
    _checkUnreadStatus();
  }

  Future<void> _checkUnreadStatus() async {
    try {
      final chatRepo = ref.read(chatRepositoryProvider);
      final status = await chatRepo.hasUnread();
      if (mounted) {
        setState(() {
          _hasUnread = status;
        });
      }
    } catch (e) {
      debugPrint("Lỗi kiểm tra trạng thái tin nhắn: $e");
    }
  }

  Future<void> _logout(BuildContext context, WidgetRef ref) async {
    final confirm = await showDialog<bool>(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Đăng xuất'),
        content: const Text('Bạn có chắc muốn đăng xuất khỏi hệ thống?'),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context, false),
            child: const Text('Hủy'),
          ),
          ElevatedButton(
            onPressed: () => Navigator.pop(context, true),
            child: const Text('Đăng xuất'),
          ),
        ],
      ),
    );

    if (confirm == true) {
      await ref.read(sessionStorageProvider).clear();
      if (!context.mounted) return;
      Navigator.of(context).pushAndRemoveUntil(
        MaterialPageRoute(builder: (_) => const AdminLoginScreen()),
        (_) => false,
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    final chatRepo = ref.watch(chatRepositoryProvider);

    final items = [
      _MenuItem(
        'Quản lý người dùng',
        Icons.people_outline,
        screen: const CustomersScreen(),
      ),
      _MenuItem(
        'Tin nhắn / hỗ trợ',
        Icons.chat_bubble_outline,
//         builder: (_) => ChatListScreen(repository: chatRepo), // Sử dụng builder nếu cần truyền repo
//         screen: const PlaceholderScreen(title: 'Tin nhắn / hỗ trợ'), // Thay thế bằng ChatListScreen thực tế
        screen: ChatListScreen(repository: chatRepo),
        showDot: _hasUnread,
      ),
      _MenuItem('Danh mục', Icons.category_outlined, screen: const PlaceholderScreen(title: 'Danh mục')),
      _MenuItem('Mã giảm giá', Icons.local_offer_outlined, screen: const PlaceholderScreen(title: 'Mã giảm giá')),
      _MenuItem('Nhân viên', Icons.badge_outlined, screen: const PlaceholderScreen(title: 'Nhân viên')),
      _MenuItem('Đánh giá', Icons.star_outline, screen: const PlaceholderScreen(title: 'Đánh giá')),
      _MenuItem('Thông báo', Icons.notifications_none_rounded, screen: const PlaceholderScreen(title: 'Thông báo')),
      _MenuItem('Báo cáo', Icons.summarize_outlined, screen: const PlaceholderScreen(title: 'Báo cáo')),
      _MenuItem('Thống kê', Icons.insights_outlined, screen: const PlaceholderScreen(title: 'Thống kê')),
      _MenuItem('Cài đặt', Icons.settings_outlined, screen: const PlaceholderScreen(title: 'Cài đặt')),
      _MenuItem('Hồ sơ', Icons.account_circle_outlined, screen: const PlaceholderScreen(title: 'Hồ sơ')),
      _MenuItem(
        'Đăng xuất',
        Icons.logout,
        onTap: () => _logout(context, ref),
        isDestructive: true,
      ),
    ];

    return Scaffold(
      backgroundColor: AdminColors.background,
      appBar: AppBar(
        title: const Text(
          'Quản trị',
          style: TextStyle(fontWeight: FontWeight.w700),
        ),
        actions: [
          IconButton(
            onPressed: _checkUnreadStatus,
            icon: const Icon(Icons.refresh),
          ),
        ],
      ),
      body: LayoutBuilder(
        builder: (context, constraints) {
          final width = constraints.maxWidth;
          final crossAxisCount = width >= 1100
              ? 4
              : width >= 800
                  ? 3
                  : width >= 600
                      ? 2
                      : 1;
          return GridView.builder(
            padding: const EdgeInsets.all(16),
            itemCount: items.length,
            gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
              crossAxisCount: crossAxisCount,
              crossAxisSpacing: 12,
              mainAxisSpacing: 12,
              childAspectRatio: crossAxisCount == 1 ? 3.4 : 1.4,
            ),
            itemBuilder: (context, index) {
              final item = items[index];
              return _MenuCard(
                item: item,
                onTap: () async {
                  if (item.onTap != null) {
                    item.onTap!();
                    return;
                  }
                  if (item.screen != null) {
                    await Navigator.push(
                      context,
                      MaterialPageRoute(builder: (_) => item.screen!),
                    );
                    _checkUnreadStatus();
                  }
                },
              )
                  .animate()
                  .fadeIn(duration: 220.ms, delay: (index * 25).ms)
                  .slideY(begin: 0.06, end: 0, duration: 220.ms, curve: Curves.easeOutCubic);
            },
          );
        },
      ),
    );
  }
}

class _MenuCard extends StatelessWidget {
  const _MenuCard({required this.item, required this.onTap});

  final _MenuItem item;
  final VoidCallback onTap;

  @override
  Widget build(BuildContext context) {
    final accentColor = item.isDestructive ? AdminColors.danger : AdminColors.primary;
    final accentBackground = accentColor.withOpacity(0.12);

    return InkWell(
      borderRadius: BorderRadius.circular(16),
      onTap: onTap,
      child: Container(
        padding: const EdgeInsets.all(14),
        decoration: BoxDecoration(
          color: AdminColors.surface,
          borderRadius: BorderRadius.circular(16),
          border: Border.all(color: AdminColors.border),
          boxShadow: [
            BoxShadow(
              color: Colors.black.withOpacity(0.04),
              blurRadius: 12,
              offset: const Offset(0, 6),
            ),
          ],
        ),
        child: Row(
          children: [
            Container(
              width: 44,
              height: 44,
              decoration: BoxDecoration(
                color: accentBackground,
                borderRadius: BorderRadius.circular(12),
              ),
              child: Icon(item.icon, color: accentColor),
            ),
            const SizedBox(width: 12),
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  Text(
                    item.title,
                    style: const TextStyle(fontWeight: FontWeight.w600),
                  ),
                  const SizedBox(height: 4),
                  Text(
                    'Truy cập nhanh',
                    style: const TextStyle(color: AdminColors.textSecondary, fontSize: 12),
                  ),
                ],
              ),
            ),
            if (item.showDot)
              Container(
                width: 10,
                height: 10,
                margin: const EdgeInsets.only(right: 8),
                decoration: const BoxDecoration(
                  color: Colors.red,
                  shape: BoxShape.circle,
                ),
              ),
            const Icon(Icons.chevron_right, color: AdminColors.textSecondary),
          ],
        ),
      ),
    );
  }
}

class _MenuItem {
  final String title;
  final IconData icon;
  final Widget? screen;
  final VoidCallback? onTap;
  final bool showDot;
  final bool isDestructive;

  _MenuItem(
    this.title,
    this.icon, {
    this.screen,
    this.onTap,
    this.showDot = false,
    this.isDestructive = false,
  });
}

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:flutter_animate/flutter_animate.dart';

import '../../../app/providers.dart';
import '../../../widgets/placeholder_screen.dart';
import '../../../theme/admin_theme.dart';
import '../../customers/presentation/customers_screen.dart';
import '../../auth/presentation/admin_login_screen.dart';
import '../../../../chat/presentation/chat_list_screen.dart';
import '../../coupons/presentation/coupons_screen.dart';

class ManagementScreen extends ConsumerStatefulWidget {
  const ManagementScreen({super.key});

  @override
  ConsumerState<ManagementScreen> createState() => _ManagementScreenState();
}

class _ManagementScreenState extends ConsumerState<ManagementScreen> {
  bool _hasUnread = false;

  @override
  void initState() {
    super.initState();
    _checkUnreadStatus();
  }

  Future<void> _checkUnreadStatus() async {
    try {
      final chatRepo = ref.read(chatRepositoryProvider);
      final status = await chatRepo.hasUnread();
      if (mounted) {
        setState(() {
          _hasUnread = status;
        });
      }
    } catch (e) {
      debugPrint("Lỗi kiểm tra trạng thái tin nhắn: $e");
    }
  }

  Future<void> _logout(BuildContext context, WidgetRef ref) async {
    final confirm = await showDialog<bool>(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Đăng xuất'),
        content: const Text('Bạn có chắc muốn đăng xuất khỏi hệ thống?'),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context, false),
            child: const Text('Hủy'),
          ),
          ElevatedButton(
            onPressed: () => Navigator.pop(context, true),
            child: const Text('Đăng xuất'),
          ),
        ],
      ),
    );

    if (confirm == true) {
      await ref.read(sessionStorageProvider).clear();
      if (!context.mounted) return;
      Navigator.of(context).pushAndRemoveUntil(
        MaterialPageRoute(builder: (_) => const AdminLoginScreen()),
        (_) => false,
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    final chatRepo = ref.watch(chatRepositoryProvider);

    final items = [
      _MenuItem(
        'Quản lý người dùng',
        Icons.people_outline,
        screen: const CustomersScreen(),
      ),
      _MenuItem(
        'Tin nhắn / hỗ trợ',
        Icons.chat_bubble_outline,
        screen: ChatListScreen(repository: chatRepo),
        showDot: _hasUnread,
      ),
      _MenuItem('Danh mục', Icons.category_outlined, screen: const PlaceholderScreen(title: 'Danh mục')),
      _MenuItem('Mã giảm giá', Icons.local_offer_outlined, screen: const CouponsScreen()),
      _MenuItem('Thông báo', Icons.notifications_none_rounded, screen: const PlaceholderScreen(title: 'Thông báo')),
      _MenuItem(
        'Đăng xuất',
        Icons.logout,
        onTap: () => _logout(context, ref),
        isDestructive: true,
      ),
    ];

    return Scaffold(
      backgroundColor: AdminColors.background,
      appBar: AppBar(
        title: const Text(
          'Quản trị',
          style: TextStyle(fontWeight: FontWeight.w700),
        ),
        actions: [
          IconButton(
            onPressed: _checkUnreadStatus,
            icon: const Icon(Icons.refresh),
          ),
        ],
      ),
      body: LayoutBuilder(
        builder: (context, constraints) {
          final width = constraints.maxWidth;
          final crossAxisCount = width >= 1100
              ? 4
              : width >= 800
                  ? 3
                  : width >= 600
                      ? 2
                      : 1;
          return GridView.builder(
            padding: const EdgeInsets.all(16),
            itemCount: items.length,
            gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
              crossAxisCount: crossAxisCount,
              crossAxisSpacing: 12,
              mainAxisSpacing: 12,
              childAspectRatio: crossAxisCount == 1 ? 3.4 : 1.4,
            ),
            itemBuilder: (context, index) {
              final item = items[index];
              return _MenuCard(
                item: item,
                onTap: () async {
                  if (item.onTap != null) {
                    item.onTap!();
                    return;
                  }
                  if (item.screen != null) {
                    await Navigator.push(
                      context,
                      MaterialPageRoute(builder: (_) => item.screen!),
                    );
                    _checkUnreadStatus();
                  }
                },
              )
                  .animate()
                  .fadeIn(duration: 220.ms, delay: (index * 25).ms)
                  .slideY(begin: 0.06, end: 0, duration: 220.ms, curve: Curves.easeOutCubic);
            },
          );
        },
      ),
    );
  }
}

class _MenuCard extends StatelessWidget {
  const _MenuCard({required this.item, required this.onTap});

  final _MenuItem item;
  final VoidCallback onTap;

  @override
  Widget build(BuildContext context) {
    final accentColor = item.isDestructive ? AdminColors.danger : AdminColors.primary;
    final accentBackground = accentColor.withOpacity(0.12);

    return InkWell(
      borderRadius: BorderRadius.circular(16),
      onTap: onTap,
      child: Container(
        padding: const EdgeInsets.all(14),
        decoration: BoxDecoration(
          color: AdminColors.surface,
          borderRadius: BorderRadius.circular(16),
          border: Border.all(color: AdminColors.border),
          boxShadow: [
            BoxShadow(
              color: Colors.black.withOpacity(0.04),
              blurRadius: 12,
              offset: const Offset(0, 6),
            ),
          ],
        ),
        child: Row(
          children: [
            Container(
              width: 44,
              height: 44,
              decoration: BoxDecoration(
                color: accentBackground,
                borderRadius: BorderRadius.circular(12),
              ),
              child: Icon(item.icon, color: accentColor),
            ),
            const SizedBox(width: 12),
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  Text(
                    item.title,
                    style: const TextStyle(fontWeight: FontWeight.w600),
                  ),
                  const SizedBox(height: 4),
                  Text(
                    'Truy cập nhanh',
                    style: const TextStyle(color: AdminColors.textSecondary, fontSize: 12),
                  ),
                ],
              ),
            ),
            if (item.showDot)
              Container(
                width: 10,
                height: 10,
                margin: const EdgeInsets.only(right: 8),
                decoration: const BoxDecoration(
                  color: Colors.red,
                  shape: BoxShape.circle,
                ),
              ),
            const Icon(Icons.chevron_right, color: AdminColors.textSecondary),
          ],
        ),
      ),
    );
  }
}

class _MenuItem {
  final String title;
  final IconData icon;
  final Widget? screen;
  final VoidCallback? onTap;
  final bool showDot;
  final bool isDestructive;

  _MenuItem(
    this.title,
    this.icon, {
    this.screen,
    this.onTap,
    this.showDot = false,
    this.isDestructive = false,
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:ute_bookstore_flutter/features/coupons/data/coupon_models.dart';

void main() {
  test('Coupon.fromJson parses fields', () {
    final json = {
      'id': 'C01',
      'code': 'SALE50',
      'discountPercent': 50,
      'discountAmount': null,
      'minOrderValue': 200000,
      'maxDiscount': 80000,
      'expiryDate': '2026-06-30T23:59:00',
      'usageLimit': 100,
      'usedCount': 12,
      'customerId': null,
      'customerName': null,
      'status': 'ACTIVE',
    };

    final coupon = Coupon.fromJson(json);
    expect(coupon.code, 'SALE50');
    expect(coupon.discountPercent, 50);
    expect(coupon.usedCount, 12);
    expect(coupon.expiryDate, isNotNull);
    expect(coupon.resolvedStatus, 'ACTIVE');
  });

  test('CouponRequest.toJson formats payload', () {
    final request = CouponRequest(
      code: 'NEW10',
      discountPercent: 10,
      discountAmount: null,
      minOrderValue: 100000,
      maxDiscount: 50000,
      expiryDate: DateTime(2026, 6, 30, 23, 59),
      usageLimit: 50,
      customerId: '',
    );

    final json = request.toJson();
    expect(json['code'], 'NEW10');
    expect(json['discountPercent'], 10);
    expect(json['discountAmount'], isNull);
    expect(json['customerId'], isNull);
  });
}
